import React, { useContext, useEffect } from 'react'
import { PageHeader } from '@/components/ui/PageHeader';
import { AuthContext } from '@/contexts/AuthContext'
import { Button, Stack } from '@mui/material';
import { ClearAccessTokenData } from '@/utils/token'
import { useUpdateKeyContext } from '@/contexts/UpdateKeyContext'
import LockIcon from '@mui/icons-material/Lock';
import { useNavigate } from '@tanstack/react-router';

const buttonStyle: React.CSSProperties = {
    width: 100,
    alignSelf: 'center'
}

export const Expired: React.FC = () => {
    const { isAuthenticated, setIsAuthenticated } = useContext(AuthContext);
    const updateKey = useUpdateKeyContext();

    const navigate = useNavigate();

    const handleResetAuth = () => {
        navigate({ to: '/login' });
    }

    useEffect(() => {
        ClearAccessTokenData();
        // Notify the router-level auth state in main.tsx so its context updates.
        // Without this the public /login route still sees `context.auth.isAuthenticated === true`
        // and redirects the user away from the login page after a Reset Auth.
        window.dispatchEvent(new Event('auth-changed'));
        if (isAuthenticated) {
            setIsAuthenticated(false);
            updateKey();
        }
    }, [])

    return (
        <Stack
            direction='column'
            spacing={2}
            sx={{ flexWrap: 'wrap', alignContent: 'center', justifyContent: 'center', height: '100%', textAlign: 'center' }}
        >
            <PageHeader
                title="Session expired!"
                subtitle="You need to login again."
            />
            <Button variant="contained" endIcon={<LockIcon />} onClick={handleResetAuth} style={buttonStyle}>
                Login
            </Button>
        </Stack>
    )
}

